export const usePayment = (options = {}) => {
  const { autoInit = true, logger, onPurchaseProcessed } = options;
  const [ready, setReady] = useState(false);
  const [iapReady, setIapReady] = useState(false);
  const [walletAvailable, setWalletAvailable] = useState(false);
  const appState = useRef(AppState.currentState);

  const init = useCallback(async () => {
    const status = await Payment.init({ logger, onPurchaseProcessed });
    setIapReady(!!status.iapReady);
    setWalletAvailable(!!status.walletBridge);
    setReady(true);
    return status;
  }, [logger, onPurchaseProcessed]);

  useEffect(() => {
    let mounted = true;
    if (!autoInit) return;

    init().catch(() => {
      if (!mounted) return;
      setReady(false);
    });

    const sub = AppState.addEventListener('change', async (next) => {
      const prev = appState.current;
      appState.current = next;
      if (prev.match(/inactive|background/) && next === 'active') {
        try {
          await Payment.processPendingPurchases({ onPurchaseProcessed });
        } catch {}
      }
    });

    return () => {
      mounted = false;
      try {
        sub?.remove?.();
      } catch {}
    };
  }, [autoInit, init, onPurchaseProcessed]);

  return useMemo(
    () => ({
      ready,
      iapReady,
      walletAvailable,
      init,
      configureProvider: Payment.configureProvider,
      getProviderConfig: Payment.getProviderConfig,
      canUseWallet: Payment.canUseWallet,
      startWalletTransaction: Payment.startWalletTransaction,
      createPaymentIntent: Payment.createPaymentIntent,
      confirmPaymentIntent: Payment.confirmPaymentIntent,
      purchaseIap: Payment.purchaseIap,
      restorePurchases: Payment.restorePurchases,
      clearSensitiveData: Payment.clearSensitiveData,
      setWalletProfile: Payment.setWalletProfile,
      getWalletProfile: Payment.getWalletProfile,
      errors: { PaymentError, PaymentErrorCode },
      constants: { PaymentProviders, WalletKinds, IapKinds },
    }),
    [ready, iapReady, walletAvailable, init]
  );
};

export const PaymentButton = ({
  title = 'Pay',
  onPress,
  disabled,
  loading,
  style,
  textStyle,
}) => {
  return (
    <TouchableOpacity
      onPress={onPress}
      disabled={disabled || loading}
      style={[styles.btn, disabled ? styles.btnDisabled : null, style]}
    >
      {loading ? <ActivityIndicator color="#fff" /> : <Text style={[styles.btnText, textStyle]}>{title}</Text>}
    </TouchableOpacity>
  );
};

